#include <stdio.h>
int main() {
    int T, N, K, A[100], count[100], size;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
            count[i] = 0;
        }
        for (int i = 0; i < N; i++) {
            count[A[i] - 1]++;
        }
        size = 0;
        for (int i = 0; i < N; i++) {
            if (count[i] >= K && A[i] != i + 1) {
                size++;
            }
        }
        printf("%d\n", size);
    }
    return 0;
}

