import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] A = new int[N];
            int[] count = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                count[A[i] - 1]++;
            }
            int size = 0;
            for (int i = 0; i < N; i++) {
                if (count[i] >= K && A[i] != i + 1) {
                    size++;
                }
            }
            System.out.println(size);
        }
    }
}

